import {React, useState, useEffect} from "react";
import EventCard from "./EventCard";
import fetchEvents from "./fetchEvents"; // Import your API function

const EventsList = () => {
	const [events, setEvents] = useState([]);
	const [loading, setLoading] = useState(true);
	const [showAll, setShowAll] = useState(false);

	useEffect(() => {
	  const loadEvents = async () => {
		const fetchedEvents = await fetchEvents(true);
		setEvents(fetchedEvents);
		setLoading(false);
	  };

	  loadEvents();
	}, []);

	return (
	  <div className="max-w-3xl xl:max-w-4xl mx-auto p-2 md:p-5 text-white">
		{loading ? (
		  <p>Loading events...</p>
		) : events.length > 0 ? (
		  <>
			{events.slice(0, showAll ? events.length : 3).map(event => (
			  <EventCard key={event.id} event={event} />
			))}
			{events.length > 3 && !showAll && (
			  <div className="mt-4 text-center">
				<button
				  type="button"
				  onClick={() => setShowAll(true)}
				  className="text-sm font-semibold text-muted-gray underline underline-offset-4 hover:text-white transition-colors"
				>
				  Show more
				</button>
			  </div>
			)}
		  </>
		) : (
		  <p class="text-center">There was an error fetching the latest information on past events. Please refresh the page.</p>
		)}
	  </div>
	);
  };

  const calendar_url = "https://calendar.google.com/calendar/u/2?cid=MWU3OWI1NTM0MzI5MGJlNWM3YmY5MzVmNjFmNDhmODkwNmIxZTkxZDI2MTE2ZWRjMjZiOWViYmZlMTZkNmNmOEBncm91cC5jYWxlbmRhci5nb29nbGUuY29t";

export default function Events() {
	return (
		<section id="pastevents" className="p-2 md:p-8 pb-2">
			<div className="max-w-6xl mx-auto">
				<h1 className="mainheader">Recent Events</h1>
				<div className="card-surface mt-4">
					<EventsList />
				</div>
